# [doc = " Host `/dev/null` must be a world-writable char device (1,3). A regular file"] # [doc = " (seen when UID 1001 accidentally creates `/dev/null`) breaks fuse-overlayfs"] # [doc = " and leaves runners stuck in `Created` with all Actions jobs queued forever."] fn assert_host_dev_null_ok () -> Result < () , String > { # [cfg (unix)] { use std :: os :: unix :: fs :: FileTypeExt ; let meta = fs :: metadata ("/dev/null") . map_err (| e | format ! ("/dev/null: {e}")) ? ; if ! meta . file_type () . is_char_device () { return Err ("/dev/null is not a character device (host corruption). \
                 Repair as root: rm -f /dev/null && mknod -m 666 /dev/null c 1 3 && chown root:root /dev/null \
                 — rootless Podman cannot start runners until this is fixed." . into () ,) ; } use std :: os :: unix :: fs :: PermissionsExt ; let mode = meta . permissions () . mode () & 0o777 ; if mode & 0o222 == 0 { return Err (format ! ("/dev/null mode {mode:o} is not writable — chmod 666 /dev/null")) ; } } Ok (()) }

fn store_token_in_git_credential (token : & str) -> Result < () , String > { let mut child = Command :: new ("git") . args (["credential" , "approve"]) . stdin (Stdio :: piped ()) . stdout (Stdio :: null ()) . stderr (Stdio :: null ()) . spawn () . map_err (| e | format ! ("git credential approve failed to start: {e}")) ? ; { let stdin = child . stdin . as_mut () . ok_or ("No stdin for git credential") ? ; writeln ! (stdin , "protocol=https
host=github.com
username=git
password={token}
") . map_err (| e | format ! ("Failed to write to git credential: {e}")) ? ; } let status = child . wait () . map_err (| e | format ! ("Failed to wait for git credential: {e}")) ? ; if ! status . success () { return Err ("git credential approve failed" . into ()) ; } Ok (()) }

fn write_env_file (path : & Path , reg_token : & str , cli : & Cli) -> Result < () , String > { let ephemeral = effective_ephemeral (cli) ; let mut opts = OpenOptions :: new () ; opts . write (true) . create (true) . truncate (true) ; # [cfg (unix)] { use std :: os :: unix :: fs :: OpenOptionsExt ; opts . mode (0o600) ; } let mut f = opts . open (path) . map_err (| e | format ! ("env file: {e}")) ? ; writeln ! (f , "REPO_URL={}
RUNNER_NAME={}
RUNNER_LABELS={}
RUNNER_EPHEMERAL={}
RUNNER_RETAIN={}
RUNNER_TOKEN={}" , github_url (cli) , cli . runner_name , cli . labels , if ephemeral { "true" } else { "false" } , if ephemeral { "false" } else { "true" } , reg_token) . map_err (| e | format ! ("env write: {e}")) ? ; # [cfg (unix)] chmod_0600 (path) ? ; Ok (()) }
